</code></pre> <pre><code>void solve() {
    int N, M, ans = 0;
    ll x, y;
    cin &gt;&gt; N &gt;&gt; M &gt;&gt; x &gt;&gt; y;
    map&lt;ll, set&lt;ll&gt;&gt; xy, yx;
    rep(i, N) {
        ll X, Y;
        cin &gt;&gt; X &gt;&gt; Y;
        xy[X].insert(Y);
        yx[Y].insert(X);
    }

    // (a,b)&lt;-&gt;(a,b+d)の道中の家を訪れる
    auto f = [&amp;](map&lt;ll, set&lt;ll&gt;&gt; &amp;ab, map&lt;ll, set&lt;ll&gt;&gt; &amp;ba, ll d, ll a, ll b) -&gt; void {
        ll b2 = b + d;
        if (b &gt; b2)
            swap(b, b2);
        auto it = ab[a].lower_bound(b);
        while (it != ab[a].end() &amp;&amp; *it &lt;= b2) {
            ans++;
            ba[*it].erase(a);
            it = ab[a].erase(it);
        }
    };
    char dir;
    ll C;
    rep(i, M) {
        cin &gt;&gt; dir &gt;&gt; C;
        ll nx = x, ny = y;
        if (dir == 'U') {
            ny = y + C;
            f(xy, yx, C, x, y);
        } else if (dir == 'D') {
            ny = y - C;
            f(xy, yx, -C, x, y);
        } else if (dir == 'L') {
            nx = x - C;
            f(yx, xy, -C, y, x);
        } else if (dir == 'R') {
            nx = x + C;
            f(yx, xy, C, y, x);
        }
        x = nx, y = ny;
    }
    cout
        &lt;&lt; x &lt;&lt; " " &lt;&lt; y &lt;&lt; " " &lt;&lt; ans &lt;&lt; endl;
}
